mapper.select:

where user_id = #{userId}
  and address_status = '0'
order by is_default desc, update_time desc, address_id desc

mapper.insert:
insert into snow_address (
    user_id, receiver_name, receiver_phone, province_code, province_name,
    city_code, city_name, district_code, district_name, detail_address, postal_code,
    is_default, address_status, remark
) values (
    #{userId}, #{receiverName}, #{receiverPhone}, #{provinceCode}, #{provinceName},
    #{cityCode}, #{cityName}, #{districtCode}, #{districtName}, #{detailAddress}, #{postalCode},
    #{isDefault}, #{addressStatus}, #{remark}
)

mapper.update:
update snow_address
receiver_name = #{receiverName}, receiver_phone = #{receiverPhone}, province_code = #{provinceCode}, province_name = #{provinceName}, city_code = #{cityCode}, city_name = #{cityName}, district_code = #{districtCode}, district_name = #{districtName}, detail_address = #{detailAddress}, postal_code = #{postalCode}, is_default = #{isDefault}, address_status = #{addressStatus}, remark = #{remark}, update_time = sysdate()
where address_id = #{addressId} and user_id = #{userId}

update snow_address
   set is_default = 'Y',
       update_time = sysdate()
 where address_id = #{addressId}
   and user_id = #{userId}
   and address_status = '0'

mapper.delete:
delete from snow_address
 where address_id = #{addressId}
   and user_id = #{userId}
